def findMinArrowShots(points: list[list[int]]) -> int:
    if not points:
        return 0

    points.sort(key=lambda x: x[1])

    arrows = 0
    last_arrow_pos = float('-inf')

    for start, end in points:
        if start > last_arrow_pos:
            arrows += 1
            last_arrow_pos = end

    return arrows
